+    #[test]
+    fn test_lifecycle_from_stats_boundaries() {
+        // Low confidence, low count → New
+        assert_eq!(PatternLifecycle::from_stats(0.0, 0), PatternLifecycle::New);
+        assert_eq!(
+            PatternLifecycle::from_stats(0.49, 100),
+            PatternLifecycle::New
